mapper.update:
UPDATE reflections SET title = #{title}, content = #{content}, visibility = #{visibility},
    status = #{status}, updated_at = NOW()
WHERE id = #{id}

mapper.select:
SELECT * FROM reflections WHERE user_id = #{userId} AND deleted_at IS NULL
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

